 1→import { NextResponse } from "next/server";
 2→import { requireStudent } from "@/lib/auth";
 3→import { prisma } from "@compass/db";
 4→import { z } from "zod";
 5→import { PromptType } from "@compass/db";
 6→
 7→const createReflectionSchema = z.object({
 8→  sessionId: z.string(),
 9→  promptText: z.string().min(1),
10→  responseText: z.string().optional(),
11→  promptType: z.nativeEnum(PromptType),
12→  isSharedWithCounselor: z.boolean().default(false),
13→});
14→
15→export async function POST(req: Request) {
16→  try {
17→    const student = await requireStudent();
18→    const body = await req.json();
19→    const data = createReflectionSchema.parse(body);
20→
21→    // Validate session belongs to student
22→    const session = await prisma.reflectionSession.findFirst({
23→      where: { id: data.sessionId, studentId: student.id },
24→    });
25→    if (!session) {
26→      return NextResponse.json({ error: "Session not found" }, { status: 404 });
27→    }
28→
29→    const wordCount = data.responseText
30→      ? data.responseText.trim().split(/\s+/).filter(Boolean).length
31→      : 0;
32→
33→    const reflection = await prisma.reflection.create({
34→      data: {
35→        studentId: student.id,
36→        sessionId: data.sessionId,
37→        promptText: data.promptText,
38→        responseText: data.responseText,
39→        promptType: data.promptType,
40→        isSharedWithCounselor: data.isSharedWithCounselor,
41→        wordCount,
42→      },
43→    });
44→
45→    return NextResponse.json(reflection, { status: 201 });
46→  } catch (error) {
47→    const message = error instanceof Error ? error.message : "Unknown error";
48→    return NextResponse.json({ error: message }, { status: 400 });
49→  }
50→}
