  8→const qstash = new Client({ token: process.env.QSTASH_TOKEN! });
  9→
 10→interface QStashPayload {
 11→  type: "WEEKLY_NUDGE_SWEEP" | "OPPORTUNITY_SWEEP" | "POST_SESSION_SYNTHESIS";
 12→  data: Record<string, unknown>;
 13→  triggeredAt: string;
 14→}
 15→
 16→async function handler(req: Request) {
 17→  const body = (await req.json()) as QStashPayload;
 18→
 19→  switch (body.type) {
 20→    case "POST_SESSION_SYNTHESIS": {
 21→      const { studentId, sessionId } = body.data as {
 22→        studentId: string;
 23→        sessionId: string;
 24→      };
 25→      await handlePostSessionSynthesis(studentId, sessionId);
 26→      break;
 27→    }
 28→
 29→    case "WEEKLY_NUDGE_SWEEP": {
 30→      await handleWeeklyNudgeSweep();
 31→      break;
 32→    }
 33→
 34→    case "OPPORTUNITY_SWEEP": {
 35→      await handleOpportunitySweep();
 36→      break;
 37→    }
 38→
 39→    default:
 40→      return NextResponse.json(
 41→        { error: "Unknown job type" },
 42→        { status: 400 }
 43→      );
 44→  }
 45→
 46→  return NextResponse.json({ success: true });
 47→}
