 49→async function handlePostSessionSynthesis(
 50→  studentId: string,
 51→  sessionId: string
 52→) {
 53→  // Fetch all relevant data
 54→  const [activities, reflections, previousProfile] = await Promise.all([
 55→    prisma.activity.findMany({
 56→      where: { studentId },
 57→      orderBy: { createdAt: "asc" },
 58→    }),
 59→    prisma.reflection.findMany({
 60→      where: { studentId },
 61→      orderBy: { createdAt: "asc" },
 62→    }),
 63→    prisma.signalProfile.findFirst({
 64→      where: { studentId },
 65→      orderBy: { createdAt: "desc" },
 66→    }),
 67→  ]);
 68→
 69→  const synthesis = await aiService.synthesizeProfile({
 70→    studentId,
 71→    sessionId,
 72→    activities,
 73→    reflections,
 74→    previousProfile,
 75→  });
 76→
 77→  // Save new signal profile
 78→  await prisma.signalProfile.create({
 79→    data: {
 80→      studentId,
 81→      interestClusters: synthesis.interestClusters as object[],
 82→      characterSignals: synthesis.characterSignals as object[],
 83→      trajectoryShifts: synthesis.trajectoryShifts as object[],
 84→      gapDetection: synthesis.gapDetection as object,
 85→      breadthScore: synthesis.breadthScore,
 86→      compressedSummary: synthesis.compressedSummary,
 87→      lastSynthesizedAt: new Date(),
 88→    },
 89→  });
 90→
 91→  // Invalidate caches
 92→  await Promise.all([
 93→    redis.del(CACHE_KEYS.signalProfile(studentId)),
 94→    redis.del(CACHE_KEYS.personalizedMap(studentId)),
 95→  ]);
 96→
 97→  // Enqueue embedding update if AI service is available
 98→  try {
 99→    const aiServiceUrl = process.env.AI_SERVICE_URL;
100→    const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";
101→    if (aiServiceUrl) {
102→      await qstash.publishJSON({
103→        url: `${appUrl}/api/webhooks/qstash`,
104→        body: {
105→          type: "EMBED_PROFILE",
106→          data: { studentId, summary: synthesis.compressedSummary },
107→          triggeredAt: new Date().toISOString(),
108→        },
109→        delay: 5,
110→      });
111→    }
112→  } catch {
113→    // Non-critical: embedding is for personalized map, not core feature
114→  }
115→}
