 8→export async function POST(
 9→  _req: Request,
10→  { params }: { params: Promise<{ id: string }> }
11→) {
12→  try {
13→    const student = await requireStudent();
14→    const { id } = await params;
15→
16→    const session = await prisma.reflectionSession.findFirst({
17→      where: { id, studentId: student.id },
18→    });
19→
20→    if (!session) {
21→      return NextResponse.json({ error: "Not found" }, { status: 404 });
22→    }
23→
24→    if (session.completedAt) {
25→      return NextResponse.json({ error: "Session already submitted" }, { status: 400 });
26→    }
27→
28→    // Mark session as complete
29→    const now = new Date();
30→    const durationSeconds = Math.floor(
31→      (now.getTime() - session.createdAt.getTime()) / 1000
32→    );
33→
34→    await prisma.reflectionSession.update({
35→      where: { id },
36→      data: {
37→        completedAt: now,
38→        durationSeconds,
39→      },
40→    });
41→
42→    // Enqueue synthesis job via QStash
43→    const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";
44→    await qstash.publishJSON({
45→      url: `${appUrl}/api/webhooks/qstash`,
46→      body: {
47→        type: "POST_SESSION_SYNTHESIS",
48→        data: {
49→          studentId: student.id,
50→          sessionId: id,
51→        },
52→        triggeredAt: now.toISOString(),
53→      },
54→      // 30 second delay to let any last writes settle
55→      delay: 30,
56→    });
57→
58→    return NextResponse.json({ success: true, completedAt: now });
59→  } catch (error) {
60→    const message = error instanceof Error ? error.message : "Unknown error";
61→    return NextResponse.json({ error: message }, { status: 400 });
62→  }
63→}
