  1→import { requireCounselor } from "@/lib/auth";
  2→import { prisma } from "@compass/db";
  3→import Link from "next/link";
  4→
  5→const FLAG_LABELS: Record<string, { label: string; color: string; description: string }> = {
  6→  never_onboarded: {
  7→    label: "Never Onboarded",
  8→    color: "text-red-600 bg-red-50 border-red-200",
  9→    description: "Has not completed the onboarding flow",
 10→  },
 11→  never_reflected: {
 12→    label: "Never Reflected",
 13→    color: "text-orange-600 bg-orange-50 border-orange-200",
 14→    description: "Completed onboarding but never submitted a reflection",
 15→  },
 16→  disengaged: {
 17→    label: "Disengaged",
 18→    color: "text-amber-600 bg-amber-50 border-amber-200",
 19→    description: "No completed reflection in 90+ days",
 20→  },
 21→  narrow_interests: {
 22→    label: "Narrow Interests",
 23→    color: "text-violet-600 bg-violet-50 border-violet-200",
 24→    description: "Breadth score below 20 — very focused on 1-2 areas",
 25→  },
 26→};
 27→
 28→export default async function FlagsPage() {
 29→  const counselor = await requireCounselor();
 30→
 31→  const students = await prisma.student.findMany({
 32→    where: { schoolId: counselor.schoolId },
 33→    include: {
 34→      signalProfiles: {
 35→        orderBy: { createdAt: "desc" },
 36→        take: 1,
 37→        select: { breadthScore: true },
 38→      },
 39→      sessions: {
 40→        orderBy: { createdAt: "desc" },
 41→        take: 1,
 42→        select: { completedAt: true },
 43→      },
 44→      privacySettings: true,
 45→    },
 46→  });
 47→
 48→  const now = new Date();
 49→  const flaggedStudents: Array<{
 50→    id: string;
 51→    firstName: string;
 52→    lastName: string;
 53→    gradeLevel: number | null;
 54→    flags: string[];
 55→    breadthScore: number | null;
 56→    lastSessionDate: Date | null;
 57→  }> = [];
 58→
 59→  for (const student of students) {
 60→    const flags: string[] = [];
 61→    const lastSession = student.sessions[0];
 62→    const profile = student.signalProfiles[0];
 63→
 64→    if (!lastSession?.completedAt) {
 65→      if (!student.onboardingCompleted) {
 66→        flags.push("never_onboarded");
 67→      } else {
 68→        flags.push("never_reflected");
 69→      }
 70→    } else {
 71→      const daysSince = Math.floor(
 72→        (now.getTime() - new Date(lastSession.completedAt).getTime()) /
 73→          (1000 * 60 * 60 * 24)
 74→      );
 75→      if (daysSince > 90) {
 76→        flags.push("disengaged");
 77→      }
 78→    }
 79→
 80→    if (
 81→      student.privacySettings?.shareBreadthScore !== false &&
 82→      profile?.breadthScore !== undefined &&
 83→      profile.breadthScore < 20
 84→    ) {
 85→      flags.push("narrow_interests");
 86→    }
 87→
 88→    if (flags.length > 0) {
 89→      flaggedStudents.push({
 90→        id: student.id,
 91→        firstName: student.firstName,
 92→        lastName: student.lastName,
 93→        gradeLevel: student.gradeLevel,
 94→        flags,
 95→        breadthScore:
 96→          student.privacySettings?.shareBreadthScore !== false
 97→            ? profile?.breadthScore ?? null
 98→            : null,
 99→        lastSessionDate: lastSession?.completedAt ?? null,
100→      });
101→    }
102→  }
103→
104→  // Sort: most flags first
105→  flaggedStudents.sort((a, b) => b.flags.length - a.flags.length);
106→
107→  return (
108→    <div className="space-y-6">
109→      <div>
110→        <h1 className="text-2xl font-bold text-[#1A1A2E]">Needs Attention</h1>
111→        <p className="text-[#6B7280] mt-1">
112→          {flaggedStudents.length} student
113→          {flaggedStudents.length !== 1 ? "s" : ""} flagged across your school
114→        </p>
115→      </div>
116→
117→      {/* Legend */}
118→      <div className="glass-card p-4">
119→        <h2 className="text-xs font-semibold text-[#6B7280] uppercase tracking-wide mb-3">
120→          Flag Types
121→        </h2>
122→        <div className="grid grid-cols-2 gap-2">
123→          {Object.entries(FLAG_LABELS).map(([key, val]) => (
124→            <div key={key} className="flex items-start gap-2">
125→              <span
126→                className={`text-[10px] font-semibold px-2 py-0.5 rounded-full border ${val.color}`}
127→              >
128→                {val.label}
129→              </span>
130→              <p className="text-[10px] text-[#9CA3AF]">{val.description}</p>
131→            </div>
132→          ))}
133→        </div>
134→      </div>
135→
136→      {/* Flagged Students */}
137→      {flaggedStudents.length === 0 ? (
138→        <div className="glass-card p-12 text-center">
139→          <div className="text-4xl mb-3">✅</div>
140→          <h3 className="font-semibold text-[#1A1A2E] mb-1">All clear!</h3>
141→          <p className="text-sm text-[#6B7280]">
142→            No students currently need attention.
143→          </p>
144→        </div>
145→      ) : (
146→        <div className="space-y-3">
147→          {flaggedStudents.map((student) => (
148→            <div key={student.id} className="glass-card p-5">
149→              <div className="flex items-start justify-between">
150→                <div className="flex-1">
151→                  <div className="flex items-center gap-3 mb-2">
152→                    <h3 className="font-semibold text-[#1A1A2E]">
153→                      {student.firstName} {student.lastName}
154→                    </h3>
155→                    {student.gradeLevel && (
156→                      <span className="text-xs text-[#9CA3AF]">
157→                        Grade {student.gradeLevel}
158→                      </span>
159→                    )}
160→                  </div>
161→
162→                  <div className="flex flex-wrap gap-1.5 mb-2">
163→                    {student.flags.map((flag) => {
164→                      const flagInfo = FLAG_LABELS[flag];
165→                      if (!flagInfo) return null;
166→                      return (
167→                        <span
168→                          key={flag}
169→                          className={`text-[10px] font-semibold px-2 py-0.5 rounded-full border ${flagInfo.color}`}
170→                        >
171→                          {flagInfo.label}
172→                        </span>
173→                      );
174→                    })}
175→                  </div>
176→
177→                  <div className="flex gap-4 text-xs text-[#9CA3AF]">
178→                    {student.lastSessionDate ? (
179→                      <span>
180→                        Last reflected{" "}
181→                        {new Date(student.lastSessionDate).toLocaleDateString(
182→                          "en-US",
183→                          { month: "short", day: "numeric", year: "numeric" }
184→                        )}
185→                      </span>
186→                    ) : (
187→                      <span>Never reflected</span>
188→                    )}
189→                    {student.breadthScore !== null && (
190→                      <span>Breadth: {Math.round(student.breadthScore)}/100</span>
191→                    )}
192→                  </div>
193→                </div>
194→
195→                <Link
196→                  href={`/students/${student.id}`}
197→                  className="text-sm text-[#3B82F6] font-medium hover:underline ml-4 flex-shrink-0"
198→                >
199→                  View profile →
200→                </Link>
201→              </div>
202→            </div>
203→          ))}
204→        </div>
205→      )}
206→    </div>
207→  );
208→}
